#include <stdio.h>
#include <stdint.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int64_t n; scanf("%lld", &n);
        int64_t ans = (n * n) / 2;
        printf("%lld\n", ans);
    }
    return 0;
}

